class SlidingWindowContext:
    """滑动窗口上下文管理器"""
    def __init__(self, max_tokens=4096, overlap=512):
        self.max_tokens = max_tokens
        self.overlap = overlap
        self.messages = []

    def add_message(self, role, content):
        self.messages.append({"role": role, "content": content})
        self._trim()

    def _trim(self):
        total = sum(len(m["content"]) // 4 for m in self.messages)
        while total > self.max_tokens and len(self.messages) > 2:
            # 保留最近消息，删除最旧的
            removed = self.messages.pop(1)  # 保留 system prompt
            total = sum(len(m["content"]) // 4 for m in self.messages)

    def get_context(self):
        return self.messages

import json
import time
from dataclasses import dataclass
from typing import Any, Optional

@dataclass
class MCPMessage:
    """MCP 消息结构"""
    from_agent: str
    to_agent: str
    action: str
    payload: dict
    message_id: str = None
    timestamp: float = None

    def __post_init__(self):
        if self.message_id is None:
            self.message_id = f"msg_{int(time.time() * 1000)}"
        if self.timestamp is None:
            self.timestamp = time.time()

    def to_json(self):
        """序列化为 JSON"""
        return json.dumps({
            'header': {
                'from': self.from_agent,
                'to': self.to_agent,
                'message_id': self.message_id,
                'timestamp': self.timestamp
            },
            'body': {
                'action': self.action,
                'payload': self.payload
            }
        }, indent=2)

    @classmethod
    def from_json(cls, json_str):
        """从 JSON 解析"""
        data = json.loads(json_str)
        return cls(
            from_agent=data['header']['from'],
            to_agent=data['header']['to'],
            action=data['body']['action'],
            payload=data['body']['payload'],
            message_id=data['header']['message_id'],
            timestamp=data['header']['timestamp']
        )

class MCPProtocol:
    """MCP 协议实现"""
    def initialize(self, provider_info):
        return MCPMessage(
            from_agent='client',
            to_agent='provider',
            action='initialize',
            payload=provider_info
        )

    def call(self, tool_name, arguments):
        return MCPMessage(
            from_agent='client',
            to_agent='provider',
            action='call',
            payload={'tool': tool_name, 'args': arguments}
        )

    def result(self, message_id, result, error=None):
        return MCPMessage(
            from_agent='provider',
            to_agent='client',
            action='result',
            payload={
                'message_id': message_id,
                'result': result,
                'error': error
            }
        )

from typing import List, Optional
from dataclasses import dataclass, field

@dataclass
class ResearchTask:
    """研究任务节点"""
    title: str
    intent: str
    query: str
    subtasks: List['ResearchTask'] = field(default_factory=list)
    summary: Optional[str] = None
    depth: int = 0

def decompose_task(llm, task: ResearchTask, max_depth=3):
    """递归分解研究任务"""
    if task.depth >= max_depth:
        return task
    if is_task_simple(task):
        return task

    prompt = f"""请将以下研究任务分解为子任务：
    任务：{task.title}
    意图：{task.intent}
    返回 JSON 数组：[{{title, intent, query}}]"""

    response = llm.generate(prompt)
    subtasks_data = parse_json(response)

    for item in subtasks_data:
        subtask = ResearchTask(
            title=item['title'],
            intent=item['intent'],
            query=item['query'],
            depth=task.depth + 1
        )
        decomposed = decompose_task(llm, subtask, max_depth)
        task.subtasks.append(decomposed)
    return task

def is_task_simple(task: ResearchTask) -> bool:
    """判断任务是否足够简单"""
    simple_kw = ['定义', '概念', '是什么', 'overview']
    return any(kw in task.title.lower() for kw in simple_kw)

def build_task_tree(topic: str, llm, max_depth=3):
    root = ResearchTask(
        title=topic,
        intent=f"全面研究{topic}",
        query=topic, depth=0
    )
    return decompose_task(llm, root, max_depth)

def count_tasks(task: ResearchTask) -> int:
    count = 1
    for sub in task.subtasks:
        count += count_tasks(sub)
    return count

